class Solution {
public:
    int minimizedStringLength(string s) {
        int n = s.size();
        vector<int> left(n, -1);
        vector<int> right(n, n);
        stack<int> st;
        for (int i = 0; i < n; i++) {
            while (!st.empty() && s[st.top()] == s[i]) {
                st.pop();
            }
            if (!st.empty()) {
                left[i] = st.top() + 1;
            }
            st.push(i);
        }
        st = stack<int>();
        for (int i = n - 1; i >= 0; i--) {
            while (!st.empty() && s[st.top()] == s[i]) {
                st.pop();
            }
            if (!st.empty()) {
                right[i] = st.top() - 1;
            }
            st.push(i);
        }
        int ans = n;
        for (int i = 0; i < n; i++) {
            ans = min(ans, n - (right[i] - left[i] + 1));
        }
        return ans;
    }
};
